import{_ as e,o as a,c as i,Q as l}from"./chunks/framework.6a72df8e.js";const C=JSON.parse('{"title":"嵌入式名词解释","description":"","frontmatter":{"title":"嵌入式名词解释","date":"2021-06-30T17:55:31.000Z","tags":["嵌入式"],"published":true,"hideInList":false,"feature":null,"isTop":false},"headers":[{"level":2,"title":"VCC (电源电压)","slug":"vcc-电源电压","link":"#vcc-电源电压","children":[]},{"level":2,"title":"VDD (器件内部的工作电压)","slug":"vdd-器件内部的工作电压","link":"#vdd-器件内部的工作电压","children":[]},{"level":2,"title":"VSS (地或电源负极)","slug":"vss-地或电源负极","link":"#vss-地或电源负极","children":[]},{"level":2,"title":"AHB (高级高性能总线)","slug":"ahb-高级高性能总线","link":"#ahb-高级高性能总线","children":[]},{"level":2,"title":"IIC (集成电路总线)","slug":"iic-集成电路总线","link":"#iic-集成电路总线","children":[]},{"level":2,"title":"SDA (I2C总线的数据信号线)","slug":"sda-i2c总线的数据信号线","link":"#sda-i2c总线的数据信号线","children":[]},{"level":2,"title":"SCL (I2C总线的时钟信号线)","slug":"scl-i2c总线的时钟信号线","link":"#scl-i2c总线的时钟信号线","children":[]},{"level":2,"title":"UART (通用异步收发传输器)","slug":"uart-通用异步收发传输器","link":"#uart-通用异步收发传输器","children":[]},{"level":2,"title":"ADC (模拟数字转换器)","slug":"adc-模拟数字转换器","link":"#adc-模拟数字转换器","children":[]}],"relativePath":"src/杂项/嵌入式名词解释.md","lastUpdated":1700455155000}'),r={name:"src/杂项/嵌入式名词解释.md"},d=l('<p>记载了在我学习单片机过程中遇到的名词</p><h2 id="vcc-电源电压" tabindex="-1">VCC (电源电压) <a class="header-anchor" href="#vcc-电源电压" aria-hidden="true">#</a></h2><p>Volt Current Condenser,在电子电路中，VCC是电路的供电电压. C=circuit 表示电路的意思, 即接入电路的电压.</p><h2 id="vdd-器件内部的工作电压" tabindex="-1">VDD (器件内部的工作电压) <a class="header-anchor" href="#vdd-器件内部的工作电压" aria-hidden="true">#</a></h2><p>D=device 表示器件的意思, 即器件内部的工作电压.</p><h2 id="vss-地或电源负极" tabindex="-1">VSS (地或电源负极) <a class="header-anchor" href="#vss-地或电源负极" aria-hidden="true">#</a></h2><p>Vss 源极电源电压, 在 CMOS 电路中指负电源, 在单电源时指零伏或接地,通常指电路公共接地端电压或电源负极。</p><h2 id="ahb-高级高性能总线" tabindex="-1">AHB (高级高性能总线) <a class="header-anchor" href="#ahb-高级高性能总线" aria-hidden="true">#</a></h2><p>Advanced High Performance Bus, 如同USB（Universal Serial Bus）一样，也是一种总线接口。 AHB主要用于高性能模块(如CPU、DMA和DSP等)之间的连接，作为SoC的片上系统总线，它包括以下一些特性：</p><ol><li>单个时钟边沿操作</li><li>非三态的实现方式</li><li>支持突发传输</li><li>支持分段传输</li><li>支持多个主控制器</li><li>可配置32位~128位总线宽度</li><li>支持字节、半字和字的传输。</li></ol><h2 id="iic-集成电路总线" tabindex="-1">IIC (集成电路总线) <a class="header-anchor" href="#iic-集成电路总线" aria-hidden="true">#</a></h2><p>Inter-Integrated Circuit,一种串行通信总线，使用多主从架构，由飞利浦公司在1980年代为了让主板、嵌入式系统或手机用以连接低速周边设备而发展。 I2C串行总线一般有两根信号线，一根是双向的数据线SDA，另一根是时钟线SCL。所有接到I2C总线设备上的串行数据SDA都接到总线的SDA上，各设备的时钟线SCL接到总线的SCL上。</p><h2 id="sda-i2c总线的数据信号线" tabindex="-1">SDA (I2C总线的数据信号线) <a class="header-anchor" href="#sda-i2c总线的数据信号线" aria-hidden="true">#</a></h2><p>SerialData</p><h2 id="scl-i2c总线的时钟信号线" tabindex="-1">SCL (I2C总线的时钟信号线) <a class="header-anchor" href="#scl-i2c总线的时钟信号线" aria-hidden="true">#</a></h2><h2 id="uart-通用异步收发传输器" tabindex="-1">UART (通用异步收发传输器) <a class="header-anchor" href="#uart-通用异步收发传输器" aria-hidden="true">#</a></h2><p>Universal Asynchronous Receiver/Transmitter,它可以将要传输的资料在串行通信与并行通信之间加以转换。，UART通常被集成于其他通讯接口的连结上，作为把并行输入信号转成串行输出信号的芯片。</p><h2 id="adc-模拟数字转换器" tabindex="-1">ADC (模拟数字转换器) <a class="header-anchor" href="#adc-模拟数字转换器" aria-hidden="true">#</a></h2><p>Analog to digital converter,通常是指一个将模拟信号转变为数字信号的电子元件。</p>',19),t=[d];function c(s,n,h,o,u,_){return a(),i("div",null,t)}const v=e(r,[["render",c]]);export{C as __pageData,v as default};
